class Admin_Model_ProductInCategory extends Admin_Model_Base_ProductInCategory {

    public function save(Doctrine_Connection $conn = null) {
        parent::save($conn);
        Admin_Model_Product::updateProductDateTime($this->Product_ID);
    }

    /**
     * @param int $productID
     * @param int $categoryID
     * @return Admin_Model_ProductInCategory
     */
    public static function createProductInCategory(int $productID, int $categoryID): Admin_Model_ProductInCategory {
        $productInCategory = new Admin_Model_ProductInCategory();
        $productInCategory->Product_ID = $productID;
        $productInCategory->Category_ID = $categoryID;
        $productInCategory->save();
        
        return $productInCategory;
    }

    public static function getProductIdsByCategoryIds(array $categoryIds): array
    {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_ProductInCategory object');
        $query->whereIn('object.Category_ID', $categoryIds);
        $data = $query->execute([], Doctrine_Core::HYDRATE_ARRAY);
        $result = [];
        foreach ($data as $item) {
            $result[] = $item['Product_ID'];
        }
        return array_unique($result);
    }

    public static function isProductInSaleCategory(int $productID): bool
    {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_ProductInCategory');
        $query->where('Category_ID=?', Admin_Model_Category::CATEGORY_SALE);
        $query->andWhere('Product_ID=?', $productID);
        return boolval($query->count());

    }

    public static function removeProductFromSaleCategory(int $productID)
    {
        $query = Doctrine_Query::create();
        $query->delete('Admin_Model_ProductInCategory');
        $query->where('Category_ID=?', Admin_Model_Category::CATEGORY_SALE);
        $query->andWhere('Product_ID=?', $productID);
        $query->execute();
    }

    public static function deleteProductInCategory(int $productID) {
        $query = Doctrine_Query::create();
        $query->delete('Admin_Model_ProductInCategory');
        $query->where('Product_ID=?', $productID);
        $query->execute();
    }

    public static function getProductCategories(int $productID) {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_ProductInCategory pic');
        $query->where('pic.Product_ID=?', $productID);
        $query->leftJoin('pic.category category');
        return $query->execute();
    }
}